// Symbol.iterator — make objects iterable
const range = {
  from: 1,
  to: 5,
  [Symbol.iterator]() {
    let current = this.from;
    const end = this.to;
    return {
      next() {
        return current <= end
          ? { value: current++, done: false }
          : { value: undefined, done: true };
      }
    };
  }
};

console.log([...range]); // [1, 2, 3, 4, 5]

// Symbol.toStringTag — customize toString()
class CustomClass {
  get [Symbol.toStringTag]() {
    return 'CustomClass';
  }
}

const instance = new CustomClass();
console.log(Object.prototype.toString.call(instance));
// '[object CustomClass]'

// Symbol.toPrimitive — customize type coercion
class Money {
  constructor(amount, currency) {
    this.amount = amount;
    this.currency = currency;
  }

  [Symbol.toPrimitive](hint) {
    if (hint === 'number') {
      return this.amount;
    }
    if (hint === 'string') {
      return this.amount + ' ' + this.currency;
    }
    return this.amount; // default
  }
}

const price = new Money(100, 'USD');
console.log(+price);       // 100 (number hint)
console.log(String(price)); // '100 USD' (string hint)
console.log(price + 50);    // 150 (default hint)

// Symbols as enum constants — guaranteed uniqueness
const Color = {
  RED: Symbol('red'),
  GREEN: Symbol('green'),
  BLUE: Symbol('blue')
};

function getHexCode(color) {
  switch (color) {
    case Color.RED:   return '#FF0000';
    case Color.GREEN: return '#00FF00';
    case Color.BLUE:  return '#0000FF';
    default:          return '#000000';
  }
}

console.log(getHexCode(Color.RED)); // '#FF0000'

